/* PDF DOWNLOAD */
const B64='';
function dlResume(){
  const bin=atob(B64),arr=new Uint8Array(bin.length);
  for(let i=0;i<bin.length;i++)arr[i]=bin.charCodeAt(i);
  const url=URL.createObjectURL(new Blob([arr],{type:'application/pdf'}));
  Object.assign(document.createElement('a'),{href:url,download:'Resume_Prajot_Nikam.pdf'}).click();
  setTimeout(()=>URL.revokeObjectURL(url),4000);
}
['dl1','dl2','dl3'].forEach(id=>{const el=document.getElementById(id);if(el)el.addEventListener('click',dlResume)});

/* CROSSHAIR CURSOR */
const cur=document.getElementById('cur'),dot=document.getElementById('cur-dot');
let mx=0,my=0;
document.addEventListener('mousemove',e=>{
  mx=e.clientX;my=e.clientY;
  cur.style.left=mx+'px';cur.style.top=my+'px';
  dot.style.left=mx+'px';dot.style.top=my+'px';
});

/* CIRCUIT BOARD CANVAS */
const canvas=document.getElementById('circuit-canvas');
const ctx=canvas.getContext('2d');
function resizeCanvas(){canvas.width=window.innerWidth;canvas.height=window.innerHeight}
resizeCanvas();window.addEventListener('resize',resizeCanvas);
const nodes=[];const COLS=['rgba(0,212,255,.25)','rgba(57,255,20,.18)','rgba(191,95,255,.18)','rgba(255,58,140,.15)','rgba(255,170,0,.15)'];
for(let i=0;i<55;i++)nodes.push({x:Math.random()*window.innerWidth,y:Math.random()*window.innerHeight,vx:(Math.random()-.5)*.18,vy:(Math.random()-.5)*.18,c:COLS[Math.floor(Math.random()*COLS.length)],r:Math.random()*2+1});
function drawCircuit(){
  ctx.clearRect(0,0,canvas.width,canvas.height);
  nodes.forEach(n=>{n.x+=n.vx;n.y+=n.vy;if(n.x<0||n.x>canvas.width)n.vx*=-1;if(n.y<0||n.y>canvas.height)n.vy*=-1});
  for(let i=0;i<nodes.length;i++){
    for(let j=i+1;j<nodes.length;j++){
      const dx=nodes[i].x-nodes[j].x,dy=nodes[i].y-nodes[j].y;
      const d=Math.sqrt(dx*dx+dy*dy);
      if(d<160){
        ctx.beginPath();ctx.moveTo(nodes[i].x,nodes[i].y);
        /* circuit lines: L-shaped */
        const mx2=nodes[i].x;const my2=nodes[j].y;
        if(Math.random()>.5){ctx.lineTo(mx2,nodes[i].y);ctx.lineTo(mx2,my2)}
        else{ctx.lineTo(nodes[j].x,nodes[i].y);ctx.lineTo(nodes[j].x,nodes[j].y)}
        ctx.lineTo(nodes[j].x,nodes[j].y);
        ctx.strokeStyle=nodes[i].c;ctx.globalAlpha=(1-d/160)*.4;ctx.lineWidth=.5;ctx.stroke();
        ctx.globalAlpha=1;
      }
    }
  }
  nodes.forEach(n=>{ctx.beginPath();ctx.arc(n.x,n.y,n.r,0,Math.PI*2);ctx.fillStyle=n.c;ctx.globalAlpha=.7;ctx.fill();ctx.globalAlpha=1});
  requestAnimationFrame(drawCircuit);
}
drawCircuit();

/* REVEAL */
const rvs=document.querySelectorAll('.rv');
rvs.forEach(el=>{const r=el.getBoundingClientRect();if(!(r.top<window.innerHeight&&r.bottom>0))el.classList.add('wa');else el.classList.add('vis')});
const obs=new IntersectionObserver(e=>{e.forEach(x=>{if(x.isIntersecting){x.target.classList.remove('wa');x.target.classList.add('vis');obs.unobserve(x.target)}})},{threshold:.06,rootMargin:'0px 0px -40px 0px'});
rvs.forEach(el=>obs.observe(el));

/* 3D TILT */
document.querySelectorAll('.pcard,.scard,.ccard,.achcard').forEach(c=>{
  c.addEventListener('mousemove',e=>{
    const r=c.getBoundingClientRect(),x=(e.clientX-r.left)/r.width-.5,y=(e.clientY-r.top)/r.height-.5;
    c.style.transform=`perspective(700px) rotateY(${x*16}deg) rotateX(${-y*12}deg) translateY(-8px) scale(1.02)`;
    c.style.boxShadow=`${-x*20}px ${-y*16}px 60px rgba(0,0,0,.7),0 20px 50px rgba(0,0,0,.5)`;
  });
  c.addEventListener('mouseleave',()=>{c.style.transform='';c.style.boxShadow=''});
});

/* SCROLL PARALLAX */
const hl=document.querySelector('.hwrap>div');
window.addEventListener('scroll',()=>{if(hl)hl.style.transform=`translateY(${scrollY*.12}px)`},{passive:true});